import Groq from "groq-sdk";

const client = new Groq();

const tools = [{
  type: "function" as const,
  function: {
    name: "get_repo_stats",
    parameters: { type: "object", properties: { repo: { type: "string" } }, required: ["repo"] }
  }
}];

const toolTurn = await client.chat.completions.create({
  model: "llama-3.3-70b-versatile",
  messages: [
    { role: "system", content: "You are a GitHub analysis assistant." },
    { role: "user",   content: "Compare vercel/next.js and facebook/react" }
  ],
  tools,
  tool_choice: "required",
  parallel_tool_calls: true,
});

const calls = toolTurn.choices[0].message.tool_calls ?? [];
const results = calls.map(c => ({
  role: "tool" as const,
  tool_call_id: c.id,
  content: JSON.stringify({ stars: Math.floor(Math.random() * 100000) })
}));

const stream = await client.chat.completions.create({
  model: "llama-3.3-70b-versatile",
  messages: [
    { role: "system",    content: "You are a GitHub analysis assistant." },
    { role: "user",     content: "Compare vercel/next.js and facebook/react" },
    toolTurn.choices[0].message,
    ...results
  ],
  stream: true,
});

for await (const chunk of stream) {
  process.stdout.write(chunk.choices[0]?.delta?.content ?? "");
}

from groq import Groq

client = Groq()

# Exhaust few-shot prompting before committing to fine-tuning
def classify_intent(user_msg: str, examples: list[dict]) -> str:
    messages = [
        {"role": "system", "content": "Classify intent as: bug_report | feature_request | question"},
        *[msg for ex in examples for msg in [
            {"role": "user", "content": ex["input"]},
            {"role": "assistant", "content": ex["label"]}
        ]],
        {"role": "user", "content": user_msg}
    ]
    resp = client.chat.completions.create(
        model="llama-3.3-70b-versatile",
        messages=messages,
        temperature=0,
        max_tokens=10
    )
    return resp.choices[0].message.content

import Groq from 'groq-sdk';

const client = new Groq();
const tools = [{ type: 'function', function: { name: 'get_price', description: 'Fetch current token price', parameters: { type: 'object', properties: { symbol: { type: 'string' } }, required: ['symbol'] } } }];
const messages = [{ role: 'user', content: 'What is the current price of ETH?' }];

for (let i = 0; i < 5; i++) {
  const res = await client.chat.completions.create({ model: 'llama-3.3-70b-versatile', messages, tools, tool_choice: 'auto' });
  const msg = res.choices[0].message;
  if (res.choices[0].finish_reason !== 'tool_calls') { console.log(msg.content); break; }
  messages.push(msg);
  for (const call of msg.tool_calls) {
    const result = call.function.name === 'get_price' ? { price: 3200 } : {};
    messages.push({ role: 'tool', tool_call_id: call.id, content: JSON.stringify(result) });
  }
}

import Groq from "groq-sdk";

const client = new Groq();

const stream = await client.chat.completions.create({
  model: "llama-3.3-70b-versatile",
  messages: [{ role: "user", content: "Explain RLHF in 3 sentences" }],
  stream: true,
});

for await (const chunk of stream) {
  const delta = chunk.choices[0]?.delta?.content ?? "";
  process.stdout.write(delta);
  if (chunk.choices[0]?.finish_reason === "stop") break;
}

import Groq from 'groq-sdk';

const groq = new Groq();

async function safeCompletion(userMessage: string): Promise<string | null> {
  const response = await groq.chat.completions.create({
    model: 'llama-3.3-70b-versatile',
    temperature: 0,
    logprobs: true,
    messages: [
      { role: 'system', content: 'Answer only from provided context. Do not speculate.' },
      { role: 'user', content: `<user_input>${userMessage}</user_input>` },
    ],
  });

  const choice = response.choices[0];
  const minProb = Math.min(
    ...(choice.logprobs?.content?.map(t => Math.exp(t.logprob)) ?? [1])
  );
  if (minProb < 0.6) return null; // low-confidence — reject

  const guard = await groq.chat.completions.create({
    model: 'llama-guard-3-8b',
    messages: [{ role: 'user', content: choice.message.content ?? '' }],
  });

  return guard.choices[0].message.content?.startsWith('safe') ? choice.message.content : null;
}
